#!/usr/bin/env python3
from datetime import datetime
from pathlib import Path
import base64
import re
import shutil
import sys

ROOT = Path.cwd()

ROUTE = ROOT / "src/app/api/sectors/route.ts"
RADAR = ROOT / "src/components/sector-radar.tsx"
DETAIL = ROOT / "src/app/sectors/[symbol]/page.tsx"
SEED = ROOT / "scripts/seed-sector-cache.py"

for path in (ROUTE, RADAR, DETAIL):
    if not path.exists():
        print(f"خطأ: الملف غير موجود: {path}")
        print("شغّل الملف من داخل apps/web")
        sys.exit(1)

stamp = datetime.now().strftime("%Y%m%d-%H%M%S")
backup_dir = Path("/tmp") / f"sector-stable-backup-{stamp}"
backup_dir.mkdir(parents=True, exist_ok=True)

for path in (ROUTE, RADAR, DETAIL):
    destination = backup_dir / path.relative_to(ROOT)
    destination.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(path, destination)

ROUTE.write_bytes(
    base64.b64decode('')
)

SEED.parent.mkdir(
    parents=True,
    exist_ok=True
)

SEED.write_bytes(
    base64.b64decode('')
)

SEED.chmod(0o755)

radar_text = RADAR.read_text(
    encoding="utf-8"
)

radar_text = re.sub(
    r"st-sector-overview-v\d+",
    "st-sector-overview-v10",
    radar_text,
)

RADAR.write_text(
    radar_text,
    encoding="utf-8"
)

detail_text = DETAIL.read_text(
    encoding="utf-8"
)

detail_text = re.sub(
    r"st-sector-detail-v\d+:",
    "st-sector-detail-v10:",
    detail_text,
)

DETAIL.write_text(
    detail_text,
    encoding="utf-8"
)

print("تم تركيب نظام القطاعات المستقر.")
print("- الموقع لا يطلب Massive عند فتح الصفحات")
print("- Massive يُستخدم فقط داخل سكربت التحديث")
print("- Finnhub للسعر الحالي فقط")
print("- البيانات التاريخية محفوظة في Supabase")
print(f"النسخة الاحتياطية: {backup_dir}")
print("الخطوة التالية: شغّل scripts/seed-sector-cache.py ثم npm run build")
